+import {readFile,writeFile,rm} from 'node:fs/promises';
+
+const read=path=>readFile(path,'utf8');
+const write=(path,value)=>writeFile(path,value);
+const replaceOnce=(source,oldValue,newValue,label)=>{
+  if(!source.includes(oldValue))throw new Error(`Missing ${label}`);
+  return source.replace(oldValue,newValue);
+};
+const replaceBetween=(source,start,end,replacement,label)=>{
+  const a=source.indexOf(start),b=source.indexOf(end,a+start.length);
+  if(a<0||b<0)throw new Error(`Missing ${label}`);
+  return source.slice(0,a)+replacement+source.slice(b);
+};
+
+let template=await read('app/src/index.template.html');
+const oldDashboard=`    <section id="dashboardView" class="card" aria-labelledby="dashboardTitle">
+      <div class="dashboardHeader">
