+          <h2 id="dashboardTitle">MY TICKETS</h2>
+          <p id="dashboardStatus" class="dashboardStatus" aria-live="polite"></p>
+        </div>
+        <div class="dashboardActions">
+          <button id="importTicketBtn" class="ghost" type="button">Import Code</button>
+          <a id="viewActiveBtn" class="button ghost" href="#view=active">View Active</a>
+          <button id="newTicketBtn" type="button">New Ticket</button>
+          <button type="button" class="ghost" data-dashboard-action="refresh">Refresh</button>
+          <button type="button" class="ghost" data-dashboard-action="select-mode">Select</button>
+          <button type="button" class="ghost filterButton" data-dashboard-action="sort-filter" aria-label="Sort and filter tickets">Sort &amp; Filter</button>
+        </div>
+      </div>
+      <div id="ticketList" class="ticketList"></div>
+    </section>`;
+const newDashboard=`    <section id="dashboardView" class="card" aria-labelledby="dashboardTitle">
+      <div class="dashboardHeader">
+        <div class="dashboardHeading">
+          <h2 id="dashboardTitle">MY TICKETS</h2>
+          <p id="dashboardStatus" class="dashboardStatus" aria-live="polite"></p>
+        </div>
+        <div class="dashboardActions">
+          <button id="importTicketBtn" class="ghost" type="button"><span>IMPORT<br>CODE</span></button>
+          <a id="viewActiveBtn" class="button ghost" href="#view=active"><span>VIEW<br>ACTIVE</span></a>
+          <button id="newTicketBtn" type="button"><span>NEW<br>TICKET</span></button>
+        </div>
+      </div>
