+name: Apply visual parity transplant
+
+on:
+  pull_request:
+    branches:
+      - main
+
+permissions:
+  contents: write
+
+jobs:
+  transplant:
+    runs-on: ubuntu-24.04
+    steps:
+      - name: Check out visual parity staging branch
+        uses: actions/checkout@v4
+        with:
+          ref: work/visual-parity-rc1
+          fetch-depth: 0
+      - name: Verify isolation
+        run: |
+          set -euo pipefail
+          git merge-base --is-ancestor 7271b5fd66b5935b3bf84037a3c44125d2490193 HEAD
+          test "$(git rev-parse origin/main)" = "d896165380191e4b9876f2ea99386808c937ec8a"
+          test -f .visual-parity/apply.mjs
+          test -f .visual-parity/prepare.mjs
+          test -f .github/workflows/apply-visual-parity.yml
+          test -z "$(git diff --name-only 3731f982987ac34a0b1d3bcf11a03b15399574a8...HEAD | grep -Ev '^(\.visual-parity/(apply|prepare)\.mjs|\.github/workflows/apply-visual-parity\.yml)$' || true)"
+      - name: Set up Node.js
+        uses: actions/setup-node@v4
+        with:
+          node-version: 24
+          cache: npm
+      - name: Prepare visual parity patch literals
+        run: node .visual-parity/prepare.mjs
+      - name: Check prepared patch syntax
+        run: node --check .visual-parity/apply.mjs
+      - name: Apply visual parity transplant
+        run: node .visual-parity/apply.mjs
+      - name: Normalize sort-filter state assignment
+        run: |
+          node <<'NODE'
+          const fs=require('fs');
+          const path='app/src/scripts/dashboard-controller.js';
+          let source=fs.readFileSync(path,'utf8');
+          const old='panel.querySelector(`input[name="dashboard-sort"][value="${this.state.sort}"]`)?.setAttribute(\'checked\',\'\');panel.querySelector(`input[name="dashboard-direction"][value="${this.state.direction}"]`)?.setAttribute(\'checked\',\'\');panel.querySelector(`input[name="dashboard-filter"][value="${this.state.filter}"]`)?.setAttribute(\'checked\',\'\');';
+          const replacement='const sort=panel.querySelector(`input[name="dashboard-sort"][value="${this.state.sort}"]`),direction=panel.querySelector(`input[name="dashboard-direction"][value="${this.state.direction}"]`),filter=panel.querySelector(`input[name="dashboard-filter"][value="${this.state.filter}"]`);if(sort)sort.checked=true;if(direction)direction.checked=true;if(filter)filter.checked=true;';
+          if(!source.includes(old))throw new Error('Missing generated sort-filter assignment');
+          source=source.replace(old,replacement).replaceAll('panel.setAttribute(','panel.setAttribute?.(');
+          fs.writeFileSync(path,source);
+          NODE
+      - name: Install exact dependencies and browsers
+        run: |
+          npm ci
+          npx playwright install --with-deps chromium webkit
+      - name: Verify modified source syntax
+        run: npm run check:syntax
+      - name: Verify controller contracts
+        run: npm run test:controllers
+      - name: Stage final source tree
+        run: git add -A
+      - name: Verify repository cleanliness
+        run: npm run verify:cleanliness
+      - name: Build canonical gold and silver
+        run: npm run build
+      - name: Verify canonical architecture
+        run: npm run verify:architecture
+      - name: Verify storage catalog and builder contracts
+        run: npm run test:components
+      - name: Verify tracker and settlement contracts
+        run: npm run test:tracker
+      - name: Verify canonical regressions
+        run: npm run test:regressions
+      - name: Verify hosting contract
+        run: npm run verify:hosting
+      - name: Verify browser and mobile matrix
+        run: npm run test:browser
+      - name: Verify integrated permanent suite
+        run: npm test
+      - name: Verify bounded source changes
+        run: |
+          set -euo pipefail
+          git diff --cached --name-status
+          test -z "$(git diff --cached --name-only | grep -Ev '^(app/src/index\.template\.html|app/src/scripts/dashboard-controller\.js|app/src/styles/app\.css|app/src/styles/dashboard\.css|\.github/workflows/apply-visual-parity\.yml|\.visual-parity/(apply|prepare)\.mjs)$' || true)"
+          test ! -e .github/workflows/apply-visual-parity.yml
+          test ! -e .visual-parity
+      - name: Commit canonical visual parity source
